#include<bits/stdc++.h>
using namespace std;
int n,m,b;
vector<pair<int,int>> mp[10010];
int f[10010],dis[10010];
bool vis[10010];
bool check(int x)
{
    priority_queue<pair<int,int>> q;
    q.push(make_pair(0,1));
    if(f[1]>x)
    {
        return false;
    }
    memset(dis,0x3f,sizeof(dis));
    dis[1]=0;
    memset(vis,0,sizeof(vis));
    while(!q.empty())
    {
        int t=q.top().second;
        q.pop();
        for(auto i:mp[t])
        {
            int v=i.first,val=i.second;
            if(!vis[v]&&f[v]<=x&&dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
    return dis[n]<=b;
}
int main()
{
    scanf("%d%d%d",&n,&m,&b);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&f[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    int l=0,r=1e9,best=-1;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            r=mid-1;
            best=mid;
        }
        else
        {
            l=mid+1;
        }
    }
    if(best==-1)
    {
        printf("AFK");
    }
    else
    {
        printf("%d",best);
    }
    return 0;
}
